import React from 'react';
import { Row, Col } from 'react-bootstrap';
// Asumimos que estos componentes existen o los crearemos a continuación.
import LoadingSpinner from './LoadingSpinner'; 
import Message from './Message'; 
import Product from './Product'; // CRÍTICO: El diseño de la tarjeta individual
import Paginate from './Paginate'; 

// Mocks para que la vista cargue y el diseño se vea completo.
const MOCK_PRODUCTS = [
  { _id: '1', name: 'Deona Pexnnices (Smartwatch)', price: 1.90, priceOld: 15.00, sku: 'DRN001', rating: 4.5, numReviews: 12, countInStock: 5, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=WATCH', productType: 'IN_HOUSE' },
  { _id: '2', name: 'Trps del Tib (VR Headset)', price: 2.90, priceOld: 10.00, sku: 'VR001', rating: 5, numReviews: 25, countInStock: 10, isOffer: true, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=VR+HEADSET', productType: 'IN_HOUSE' },
  { _id: '3', name: 'Pnda de Tvler (Smartwatch)', price: 2.90, priceOld: 20.00, sku: 'DRN002', rating: 3.5, numReviews: 8, countInStock: 0, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=WATCH', productType: 'IN_HOUSE' },
  { _id: '4', name: 'Datns eq Pcnitations (VR Glasses)', price: 2.90, priceOld: 12.99, sku: 'DRN003', rating: 4, numReviews: 15, countInStock: 3, image: 'https://placehold.co/400x300/F1F5F9/0F172A?text=VR+GLASSES', productType: 'IN_HOUSE' },
];

// Si no se pasan props, usamos los Mocks.
const ProductList = ({ products = MOCK_PRODUCTS, loading, error, pages, page, setPage }) => {
    
    // Si está cargando, muestra el spinner.
    if (loading) {
        return <div className="d-flex justify-content-center py-5"><LoadingSpinner /></div>;
    }

    // Si hay un error, muestra el mensaje de error.
    if (error) {
        return <Message variant="danger">Error al cargar productos: {error}</Message>;
    }

    return (
        <>
            {/* Si no hay productos */}
            {(!products || products.length === 0) ? (
                <div className="text-center py-5 border border-dashed border-gray-300 rounded-xl">
                    <i className="fas fa-box-open fa-4x text-gray-300 mb-4"></i>
                    <h4 className="text-gray-600 font-bold">¡Lo sentimos! No hay productos en esta sección.</h4>
                </div>
            ) : (
                <>
                    {/* Renderizado de la cuadrícula de productos */}
                    <Row>
                        {products.map((product) => (
                            // Layout Responsivo: 1 en móvil, 2 en tablet, 4 en desktop (para que quepan 4 en una fila)
                            <Col key={product._id} xs={12} sm={6} md={4} lg={3} className="d-flex align-items-stretch mb-5">
                                <Product product={product} />
                            </Col>
                        ))}
                    </Row>
                    
                    {/* Paginación (solo si hay más de una página) */}
                    {(pages > 1) && (
                        <div className="d-flex justify-content-center mt-5">
                            <Paginate pages={pages} page={page} setPage={setPage} />
                        </div>
                    )}
                </>
            )}
        </>
    );
};

export default ProductList;
